        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(_preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(msg.value == cost * amount, "Incorrect payment");

        supply += amount;
        _preSaleWalletMinted[msg.sender] += amount;
    }

