        require(_currentSaleStatus == SaleStatus.PublicSale, "Public sale not active");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == cost * amount, "Incorrect payment");

        supply += amount;
    }

    function preSaleWalletMinted(address user) public view returns (uint256) {
        return _preSaleWalletMinted[user];
    }

    function currentSaleStatus() public view returns (SaleStatus) {
        return _currentSaleStatus;
    }
}
